sql:
SELECT COUNT(*) AS verified_count
FROM verification_statuses
WHERE verification_name = 'Verified';

SELECT address
FROM loan_addresses
WHERE earliest_cr_line > '2018-01-01';

SELECT COUNT(*) 
FROM loan_purposes 
WHERE purpose_name = 'credit_card';

SELECT transaction_type
FROM loan_transactions
WHERE processed_by = 0;

SELECT SUM(amount) AS total_amount
FROM loan_transactions
WHERE processed_by = 0 AND transaction_status = 'successful';

SELECT purpose_name
FROM loan_purposes
WHERE purpose_id = 0;

SELECT transaction_type, SUM(amount) AS total_amount
FROM loan_transactions
GROUP BY transaction_type;

SELECT full_name, email
FROM loan_officers
ORDER BY created_at ASC;

SELECT COUNT(*) AS count_of_highest_quality_grades
FROM loan_grades
WHERE description = 'Highest credit quality';

SELECT purpose_name
FROM loan_purposes
WHERE purpose_id <= 0;

SELECT sub_grade_name, grade_id, description
FROM loan_sub_grades
WHERE sub_grade_id = 0;

SELECT grade_name, description
FROM loan_grades
WHERE grade_id = 0;

SELECT grade_name
FROM loan_grades
WHERE grade_name = 'A';

SELECT verification_name
FROM verification_statuses
WHERE verification_id = 0;

SELECT COUNT(*) 
   FROM loan_addresses 
   WHERE state = 'AZ';
